import{_ as e,o,c as t,a2 as a}from"./chunks/framework.Crpw6aS5.js";const s=JSON.parse('{"title":"2020年致股东信 - 翻译版","description":"","frontmatter":{},"headers":[],"relativePath":"01_letters/2020年/翻译.md","filePath":"01_letters/2020年/翻译.md"}'),r={name:"01_letters/2020年/翻译.md"};function l(u,p,n,h,i,q){return o(),t("div",null,[...p[0]||(p[0]=[a('<h1 id="_2020年致股东信-翻译版" tabindex="-1">2020年致股东信 - 翻译版 <a class="header-anchor" href="#_2020年致股东信-翻译版" aria-label="Permalink to &quot;2020年致股东信 - 翻译版&quot;">​</a></h1><p><em>原文来源：Berkshire Hathaway 2020年致股东信</em></p><hr><p>伯克希尔业绩 vs. 标普500 每股市场价值年度百分比变化 伯克希尔 标普500（含股息） 年份 1965......................................................................... 49.5 10.0 1966......................................................................... (3.4) (11.7) 1967......................................................................... 13.3 30.9 1968......................................................................... 77.8 11.0 1969......................................................................... 19.4 (8.4) 1970......................................................................... (4.6) 3.9 1971......................................................................... 80.5 14.6 1972......................................................................... 8.1 18.9 1973......................................................................... (2.5) (14.8) 1974......................................................................... (48.7) (26.4) 1975......................................................................... 2.5 37.2 1976......................................................................... 129.3 23.6 1977......................................................................... 46.8 (7.4) 1978......................................................................... 14.5 6.4 1979......................................................................... 102.5 18.2 1980......................................................................... 32.8 32.3 1981......................................................................... 31.8 (5.0) 1982......................................................................... 38.4 21.4 1983......................................................................... 69.0 22.4 1984......................................................................... (2.7) 6.1 1985......................................................................... 93.7 31.6 1986......................................................................... 14.2 18.6 1987......................................................................... 4.6 5.1 1988......................................................................... 59.3 16.6 1989......................................................................... 84.6 31.7 1990......................................................................... (23.1) (3.1) 1991......................................................................... 35.6 30.5 1992......................................................................... 29.8 7.6 1993......................................................................... 38.9 10.1 1994......................................................................... 25.0 1.3 1995......................................................................... 57.4 37.6 1996......................................................................... 6.2 23.0 1997......................................................................... 34.9 33.4 1998......................................................................... 52.2 28.6 1999......................................................................... (19.9) 21.0 2000......................................................................... 26.6 (9.1) 2001......................................................................... 6.5 (11.9) 2002......................................................................... (3.8) (22.1) 2003......................................................................... 15.8 28.7 2004......................................................................... 4.3 10.9 2005......................................................................... 0.8 4.9 2006......................................................................... 24.1 15.8 2007......................................................................... 28.7 5.5 2008......................................................................... (31.8) (37.0) 2009......................................................................... 2.7 26.5 2010......................................................................... 21.4 15.1 2011......................................................................... (4.7) 2.1 2012......................................................................... 16.8 16.0 2013......................................................................... 32.7 32.4 2014......................................................................... 27.0 13.7 2015......................................................................... (12.5) 1.4 2016......................................................................... 23.4 12.0 2017......................................................................... 21.9 21.8 2018......................................................................... 2.8 (4.4) 2019......................................................................... 11.0 31.5 2020......................................................................... 2.4 18.4 复合年收益——1965至2020年 …………………………………… 20.0% 10.2% 总收益——1964至2020年 ……………………………………… 2,810,526% 23,454%</p><p>注：数据均为日历年，以下年份除外：1965年和1966年为截至9月30日的年度；1967年为截至12月31日的15个月。</p><p>第2页</p><p>伯克希尔·哈撒韦公司 致伯克希尔·哈撒韦公司全体股东：</p><p>按照通用会计准则（通常简称为&quot;GAAP&quot;），伯克希尔在2020年实现了425亿美元的净利润。该数字由四部分构成：经营收益219亿美元、已实现资本收益49亿美元、因所持股票未实现资本净收益增加而产生的267亿美元收益，以及若干子公司和关联企业资产减值所导致的110亿美元亏损。以上所有项目均为税后口径。</p><p>经营收益才是我们最看重的指标——即使在经营收益并非GAAP总额中最大项的时期亦是如此。伯克希尔的重点在于两方面：一是不断提高经营收益这一板块的收入，二是收购大型且具有有利地位的企业。然而去年，我们两个目标均未达成：伯克希尔没有进行任何规模可观的收购，经营收益下降了9%。不过，我们通过留存收益以及回购约5%的公司股票，提升了伯克希尔的每股内在价值。</p><p>与资本收益或亏损相关的两项GAAP项目（无论已实现或未实现）每年都会因股票市场的波动而剧烈变化。无论今日的数据如何，我的长期搭档<a href="/04_people/查理·芒格.html">查理·芒格</a>和我都坚信，从长远来看，伯克希尔投资组合中的资本收益将成为一笔可观的财富。</p><p>正如我多次强调的，Charlie和我将伯克希尔持有的可交易股票——截至2020年底市值达2810亿美元——视为一揽子企业的集合。我们虽不控制这些公司的运营，但与他们共同分享长期繁荣。然而从会计角度，我们按比例享有的这些公司的收益并不计入伯克希尔的收入。只有被投资企业实际支付给我们的股息才会在我们的账簿上记录。在GAAP口径下，被投资企业为我们代为留存的巨额资金处于&quot;隐形&quot;状态。</p><p>然而，眼不见不能心不想：这些未入账的留存收益通常正在为伯克希尔创造大量价值——极高的价值。被投资企业利用这些留存资金拓展业务、进行收购、偿还债务，而且往往还会回购自家股票（此举将增加我们对其未来收益的份额）。</p><p>正如我们在去年致股东信中所指出的，留存收益在美国企业的发展历程中始终发挥着推动力量。Carnegie和Rockefeller时代奏效的方法，多年以来同样为数百万股东带来了可观的回报。</p><hr><p>查理和我希望我们的企业集团拥有全部或部分具有良好经济特征和优秀管理层 的多元业务组合。然而，伯克希尔是否控股这些企业，对我们来说并不重要。 我花了一些时间才明白这个道理。但是，查理——以及我在伯克希尔继承的纺织 业务上长达二十年的挣扎——最终说服我：拥有一家优秀企业的不控股股权，比 经营一家边缘企业百分之百的股权更有利可图，也更有乐趣，且省心得多。 基于这些原因，我们的企业集团将保持控制和非控制业务的组合。查理和我 将简单地根据公司的持久竞争优势、管理层的能力和品格以及价格，把你们的资 本投入到我们认为最有意义的地方。 如果这种策略几乎不需要我们付出努力，那就更好了。与跳水比赛的评分制度 不同的是，商业活动中不会因为你完成了&quot;高难度&quot;动作而获得额外分数。此外， 正如罗纳德·里根所警告的那样：&quot;据说努力工作不会杀死任何人，但我说为何 要冒险呢？&quot;</p><p>珍宝业务及如何增加你们的份额 在A-1页，我们列出了伯克希尔的子公司——年末雇佣36万员工的多样化企 业组合。你们可以在本报告后面的10-K文件中阅读更多关于这些控股业务的信 息。我们持有的非控股重大投资列于本信函第7页。该投资组合同样规模庞大且 多样化。 然而，伯克希尔的大部分价值集中在四家企业中——三家控股企业和一家我 们仅持有5.4%股权的企业。这四家企业都是珍宝。 价值最大的是我们的财产/意外险业务，这一直是伯克希尔53年来的核心业 务。我们的保险家族在保险领域独树一帜。其管理者<a href="/04_people/阿吉特·贾恩.html">阿吉特·贾恩</a>（<a href="/04_people/阿吉特·贾恩.html">阿吉特·贾恩</a>）亦是如此，他于1986年加入伯克希尔。 整体而言，我们的保险舰队运营的资本远超全球任何竞争对手。这种财务实 力，加上伯克希尔从非保险业务每年获得的巨额现金流，使我们的保险公司能 够安全地遵循股票投资占比较高的投资策略，而这对绝大多数保险公司来说是 不可行的。由于监管和信用评级的限制，这些竞争对手必须专注于债券投资。 而如今债券并非明智之选。你能相信吗？年末收益率仅为0.93%的10年期 美国国债，其收益较1981年9月的15.8%已下跌94%。在某些重要大国，如 德国和日本，投资者在数万亿美元的主权债务上获得负回报。全球固定收益投资 者——无论是养老基金、保险公司还是退休人员——都面临着黯淡的未来。</p><p>一些保险公司以及其他债券投资者可能试图通过转向由不稳定借款人担保的 债券来提高目前少得可怜的投资回报。然而，风险贷款并非利率不足的解决方 案。三十年前，曾经强大的储蓄和贷款行业正是部分由于忽视这一原则而自我 毁灭。 伯克希尔目前拥有1380亿美元的保险&quot;浮存金&quot;——这些资金虽然不归 我们所有，但我们可以自由支配，用于投资债券、股票或现金等价物（如美国 国库券）。浮存金与银行存款有些相似：现金每日流入流出保险公司，但其持 有总额变化甚微。伯克希尔持有的巨额资金可能在多年内保持在其当前水平附 近，且从累计来看对我们是无成本的。当然，这种理想状况可能改变——但长 久来看，我看好我们的胜算。 我在年度致股东信中反复——有人可能会说无穷尽地——解释我们的保险业 务。因此，今年我请希望了解更多关于我们保险业务和&quot;浮存金&quot;的新股东阅读 2019年报告的相关部分，转载于A-2页。理解我们保险活动中的风险和机会都 很重要。 我们第二和第三有价值的资产——目前基本上难分伯仲——是伯克希尔100% 拥有的BNSF（按货运量计美国最大的铁路公司）以及我们持有的5.4%的苹果股 权。第四位是我们91%拥有的伯克希尔能源公司（Berkshire Hathaway Energy， 简称&quot;BHE&quot;）。这是一家非常不寻常的公用事业企业，在我们持有的21年间， 其年度收益从1.22亿美元增长到34亿美元。 关于BNSF和BHE，我将在本信函后面有更多阐述。现在，我想谈谈伯克希 尔将定期使用的一种做法，以增强你们对其&quot;四大&quot;资产以及其他众多资产的 权益。 *****</p><p>去年，我们通过回购相当于80,998股&quot;A&quot;股的方式展示了伯克希尔对各类 资产的热情，花费247亿美元。此举使你们在伯克希尔所有企业中的所有权增 加了5.2%，而无需你们掏一分钱。 根据查理和我长期推荐的标准，我们进行这些回购，因为我们相信这些回购 将提升持续股东的每股内在价值，并使伯克希尔拥有充足的资金应对任何可能 出现的机遇或问题。 我们绝不认为伯克希尔应该以任意价格回购股票。我强调这一点，因为美 国CEO们在股价上涨时比股价下跌时更积极地投入公司资金用于回购，这一记 录令人尴尬。我们的做法恰恰相反。 伯克希尔对苹果的投资清楚地说明了回购的力量。我们于2016年末开始购 买苹果股票，到2018年7月初，已持有略多于10亿股苹果股票（经拆股调整后）。 需要说明的是，我指的是伯克希尔一般账户中持有的投资，不包括随后已出售 的一个规模很小且单独管理的苹果股票持仓。当我们在2018年中期完成购买 时，伯克希尔一般账户持有苹果5.2%的股权。 我们该持仓的成本为360亿美元。自那时以来，我们既享受了定期股息，平 均每年约7.75亿美元，又在2020年通过出售一小部分持仓额外获得了110亿 美元。 尽管进行了上述出售——瞧！——伯克希尔现在持有苹果5.4%的股权。这 一增加对我们毫无成本，原因是苹果持续回购其股票，从而大幅减少了其在外 流通股数。 但这还不是全部好消息。因为在这两年半期间我们也回购了伯克希尔股票， 你们现在间接拥有的苹果资产和未来收益比2018年7月时多出了10%。 这种令人愉悦的动态仍在持续。伯克希尔自年末以来已回购更多股票，未 来可能进一步减少其流通股数。苹果也公开表示有意回购其股票。随着这些减 少发生，伯克希尔股东不仅将在我们的保险集团、BNSF和BHE中拥有更大的权 益，而且将发现他们对苹果的间接所有权也在增加。 回购的数学计算进展缓慢，但长期来看可能很强大。这一过程为投资者提供 了一种拥有优秀企业不断扩大的份额的简单方式。 正如性感的梅·韦斯特向我们保证的：&quot;好东西太多可以……太棒了。&quot;</p><p>投资 以下我们列出年底时市值最大的十五项普通股投资。我们排除卡夫亨氏的持 股——325,442,152股——因为伯克希尔是控制权集团的成员，必须使用&quot;权益 法&quot;对该投资进行会计处理。在其资产负债表上，伯克希尔以GAAP数据133亿 美元列示卡夫亨氏持仓，这一金额代表伯克希尔在2020年12月31日应占卡夫 亨氏经审计的净资产份额。但请注意，我们当日持有的股份市值仅为113亿美 元。</p><p>2020年12月31日 公司名称 持股数* 占公司 持股成本** 市值 股权比例 (百万美元) AbbVie Inc. 25,533,082 1.4% $2,333 $2,736 American Express Company 151,610,700 18.8% 1,287 18,331 Apple Inc. 907,559,761 5.4% 31,089 120,424 Bank of America Corp. 1,032,852,006 11.9% 14,631 31,306 The Bank of New York Mellon Corp. 66,835,615 7.5% 2,918 2,837 BYD Co. Ltd. 225,000,000 8.2% 232 5,897 Charter Communications, Inc. 5,213,461 2.7% 904 3,449 Chevron Corporation 48,498,965 2.5% 4,024 4,096 The Coca-Cola Company 400,000,000 9.3% 1,299 21,936 General Motors Company 52,975,000 3.7% 1,616 2,206 Itochu Corporation 81,304,200 5.1% 1,862 2,336 Merck &amp; Co., Inc. 28,697,435 1.1% 2,390 2,347 Moody&#39;s Corporation 24,669,778 13.2% 248 7,160 U.S. Bancorp 148,176,166 9.8% 5,638 6,904 Verizon Communications Inc. 146,716,496 3.5% 8,691 8,620 其他*** 29,458 40,585 按市值列示的权益投资合计 $108,620 $281,170</p><ul><li>不含伯克希尔子公司养老基金持有的股份。 ** 这是我们的实际购买价格，也是我们的税基。 *** 包括对西方石油公司（Occidental Petroleum）的100亿美元投资，包括优先股和 购买普通股的认股权证，该组合目前估值90亿美元。</li></ul><p>双城记 成功故事在美国遍地开花。自我国诞生以来，凭借创意、雄心——往往还有 少量资本——的个人，通过创造新事物或改善老产品的客户体验，取得了超越 梦想的成功。 查理和我走遍全国，与其中许多人或其家族携手。1972年，我们在西海岸 开始了这一惯例，收购了喜诗糖果（See&#39;s Candy）。一个世纪前，玛丽·喜诗 （Mary See）开始推出一款她用特殊配方重新改良的传统产品。她的商业计划 还包括由友好销售员驻守的古朴店铺。她在洛杉矶的第一家小门店最终发展到 数百家店铺，遍布整个西部。 今天，喜诗夫人的产品继续令消费者愉悦，为成千上万的男女提供终身就 业机会。伯克希尔的职责simply就是不干预公司的成功。当一家企业生产和分 销非必需消费品时，客户就是老板。百年后，客户传递给伯克希尔的信息依然 清晰：&quot;别动我的糖果。&quot;（网址是<a href="https://www.sees.com/%EF%BC%9B%E8%AF%B7%E5%B0%9D%E5%B0%9D%E8%8A%B1%E7%94%9F%E8%84%86%E7%B3%96%E3%80%82%EF%BC%89" target="_blank" rel="noreferrer">https://www.sees.com/；请尝尝花生脆糖。）</a> 让我们横跨大陆来到华盛顿特区。1936年，利奥·古德温（Leo Goodwin） 与妻子莉莉安（Lillian）坚信汽车保险——一种通常从代理人那里购买的标准 化产品——可以以更低的价格直接销售。凭借10万美元，他们与资本规模超过 自己1000倍的巨型保险公司展开了竞争。政府雇员保险公司（Government Employees Insurance Company，后简称GEICO）就此起步。 幸运的是，我在70年前就接触到了这家公司的潜力。它立即成为我的投资初 恋。你们知道后续的故事：伯克希尔最终成为GEICO的100%所有者，这家84岁 的公司仍在不断微调——但不变地——践行着利奥和莉莉安的愿景。 然而，公司的规模发生了变化。1937年，即其首个完整运营年度，GEICO的</p><hr><p>2.38亿美元。去年这一数字为350亿美元。</p><p>如今，随着金融、媒体、政府和科技企业大量聚集在沿海地区，人们很容易忽视中美洲地区正在发生的诸多奇迹。让我们聚焦两个社区，它们充分展示了我国各地人才济济、雄心勃勃的事实。</p><p>你不会惊讶我以奥马哈开场。</p><p>1940年，杰克·林格瓦特（Jack Ringwalt）——奥马哈中央高中毕业生（也是Charlie、我父亲、我第一任妻子、我们三个孩子和两个孙辈的校友）——决定创办一家产险公司，初始资本为12.5万美元。</p><p>杰克的梦想近乎荒谬：他这家名为“国家保险”（National Indemnity）的小型公司，要与资本雄厚的巨型保险公司竞争。此外，这些竞争对手都已建立完善的全国性代理网络，资金充裕、历史悠久。</p><p>按照杰克的计划，国家保险与GEICO不同，它只能依赖愿意接受它的代理机构，因此在业务获取上没有任何成本优势。为了克服这些巨大障碍，国家保险专注于&quot;另类&quot;风险——这些风险被&quot;大玩家&quot;们认为无足轻重。结果，这个看似不可能的战略竟然成功了。</p><p>杰克诚实、精明、讨人喜欢，而且有点 quirky。特别的是，他不喜欢监管者。当他偶尔对监管部门的监督感到厌烦时，就会萌生出售公司的念头。</p><p>幸运的是，在这种情况下我就在附近。杰克喜欢加入伯克希尔的想法，我们于1967年达成交易，前后握手仅用了15分钟。我从未要求进行审计。</p><p>如今，国家保险是全球唯一愿意承保某些巨型风险的公司。是的，它仍然设在奥马哈，距离伯克希尔总部仅几英里。</p><p>多年来，我们从奥马哈家族手中收购了四家额外业务，其中最著名的是内布拉斯加家具商场（&quot;NFM&quot;）。公司创始人罗斯·<a href="/04_people/B夫人.html">B夫人</a>（<a href="/04_people/B夫人.html">B夫人</a>，&quot;B女士&quot;）于1915年作为俄罗斯移民抵达西雅图，既不识字也不会说英语。几年后她搬到奥马哈，到1936年已攒下2500美元，创办了一家家具店。</p><p>竞争对手和供应商都无视她，当时的判断似乎有理有据：二战使她的业务陷入停滞，1946年底公司净资产仅增长到72,264美元。现金——无论是库存现金还是银行存款——仅有50美元（这不是笔误）。</p><p>然而，1946年的数据中有一项无价资产未被记录：B女士的独子路易·<a href="/04_people/B夫人.html">B夫人</a>（<a href="/04_people/B夫人.html">B夫人</a>）在美国陆军服役四年后回到了店里。路易在诺曼底登陆日后在奥马哈海滩作战，在突出部之役中负伤获得紫心勋章，最终在1945年11月平安回国。</p><p>B女士和路易重逢后，NFM便势不可挡。在梦想的驱动下，母子俩日以继夜地工作。结果成就了一个零售业的奇迹。</p><p>到1983年，两人已创造出价值6000万美元的业务。那一年，在我生日那天，伯克希尔收购了NFM 80%的股份，同样未经审计。我信任<a href="/04_people/B夫人.html">B夫人</a>家族成员来经营业务；第三代和第四代仍在经营。B女士一直工作到103岁——用Charlie和我的话来说，这是个极其荒唐的退休年龄。</p><p>NFM现拥有全美最大的三家家居用品店。2020年，每家店都创下销售纪录，尽管因COVID-19疫情，NFM门店关闭超过六周。</p><p>这个故事的后记完美诠释了一切：当B女士的大家庭聚在一起过节用餐时，她总是要求大家在吃饭前唱一首歌。她的选择始终不变：欧文·柏林（Irving Berlin）的《上帝保佑美国》。</p><p>让我们往东一点，移到田纳西州第三大城市诺克斯维尔。在那里，伯克希尔拥有两家杰出公司的股份——克莱顿房屋公司（<a href="/04_people/凯文·克莱顿.html">凯文·克莱顿</a> Homes，100%持有）和旅行者中心（Pilot Travel Centers，目前持有38%，但到2023年将增至80%）。</p><p>两家公司都由毕业于田纳西大学、留在诺克斯维尔的年轻人创办。他们都没有可观的资本，也没有富有的父母。</p><p>那又怎样？如今，克莱顿和Pilot的年度税前收益均超过10亿美元。两家公司合计雇佣约4.7万名男女员工。</p><p>吉姆·克莱顿（Jim <a href="/04_people/凯文·克莱顿.html">凯文·克莱顿</a>）在多次创业尝试后，于1956年以微薄资金创办了克莱顿房屋公司，而&quot;大吉姆&quot;·哈斯拉姆（&quot;Big Jim&quot; Haslam）于1958年以6000美元购买了一个服务站，创办了后来的旅行者中心。后来，两人都将具有同样激情、价值观和头脑的儿子引入公司。有时成功真的会代代相传。</p><p>&quot;大吉姆&quot;·哈斯拉姆现已90岁，最近写了一本激励人心的书，书中讲述了吉姆·克莱顿的儿子凯文（Kevin）如何鼓励哈斯拉姆家族将Pilot的大部分股份出售给伯克希尔。每个零售商都知道，满意的顾客是门店最好的推销员。企业易手时也是如此。</p><p>下次你飞越诺克斯维尔或奥马哈时，请向克莱顿家族、哈斯拉姆家族、布鲁姆家族以及我国各地无数成功的企业家们致敬。这些创业者需要美国的发展框架——1789年制定的一项独特实验——来实现他们的潜能。反过来，美国也需要像吉姆·C.、吉姆·H.、B女士和路易这样的公民，来完成开国元勋们所追求的奇迹。</p><p>如今，世界各地许多人都在创造类似的奇迹，惠及全人类的广泛繁荣。然而，在其短暂的232年历史中，没有任何孵化器能像美国这样充分释放人类潜能。尽管经历过一些严重的挫折，我国经济进步仍令人惊叹不已。</p><p>此外，我们仍保持宪法所载的&quot;建立更完美联邦&quot;的崇高理想。实现这一理想的进程缓慢、不均衡、常常令人沮丧。然而，我们一直在前进，并将继续前行。</p><p>我们坚定的结论是：永远不要押注美国。</p><p>伯克希尔 partnership</p><p>伯克希尔是特拉华州公司，我们的董事必须遵守该州法律。其中一项要求是，董事会成员必须以公司和股东的最佳利益行事。我们的董事都认同这一原则。</p><p>此外，伯克希尔董事们自然希望公司能令客户满意，培养和奖励36万名员工的才能，与贷款人诚实往来，并被视为我们运营所在许多城市和好公民。我们高度重视这四个重要群体。</p><p>然而，这些群体在决定股息、战略方向、CEO人选或收购与剥离等事项上没有投票权。这些责任完全由伯克希尔的董事会承担，他们必须忠实地代表公司和所有者的长期利益。</p><p>除了法律要求，Charlie和我对伯克希尔的众多个人股东负有特殊义务。一点个人经历或许有助于你理解我们不同寻常的深厚情感，以及这如何影响我们的行为。</p><p>在我加入伯克希尔之前，我通过一系列合伙企业为许多人管理资金，最初的三家合伙企业成立于1956年。随着时间推移，多个实体的使用变得笨重，1962年我们将12家合伙企业合并为一个单一实体——<a href="/04_people/沃伦·巴菲特.html">沃伦·巴菲特</a>合伙有限公司（&quot;BPL&quot;）。</p><p>到那一年，我自己的钱以及我妻子的钱，几乎都已与众多有限合伙人的资金一起投资。我不领取工资或费用。作为普通合伙人，我只有在有限合伙人获得超过6%的年度门槛回报后才能获得报酬。如果回报未能达到该水平，差额将结转至我未来的利润份额。（幸运的是，这从未发生过：合伙企业回报始终超过6%的&quot;基准&quot;。）岁月流逝，我父母、兄弟姐妹、姑姨叔舅、表亲和姻亲的大量资源都投入了合伙企业。</p><p>Charlie于1962年创立了他的合伙企业，经营方式与我大体相同。我们都没有机构投资者，我们合伙人中也鲜有财务专业人士。加入我们企业的人simply信任我们，把他们的钱当作自己的钱来对待。这些人——无论凭直觉还是朋友的建议——正确地判断到Charlie和我对永久性资本损失极度厌恶，如果我们不期望为他们合理地管理资金，就不会接受他们的钱。</p><p>我在BPL于1965年收购伯克希尔控制权后，阴差阳错地进入了商业管理领域。随后，在1969年，我们决定解散BPL。年底后，合伙企业按比例分配了所有现金和三只股票，其中价值最大的是BPL持有的伯克希尔70.5%权益。</p><p>与此同时，Charlie于1977年结束了他的业务。他分配给合伙人的资产中，包括他合伙企业、伯克希尔和我共同控制的主要权益——蓝章邮票（Blue Chip Stamps）。蓝章也是我的合伙企业解散时分配的三只股票之一。</p><p>1983年，伯克希尔与蓝章合并，从而将注册股东基数从1900人扩大至2900人。Charlie和我希望所有人——老股东、新股东和潜在股东——都能了解相同的情况。因此，1983年年报开篇即阐述了伯克希尔的&quot;主要商业原则&quot;。第一条原则开头写道：&quot;尽管我们的形式是公司，但我们的态度是合伙。&quot;这一定义了我们在1983年的关系；今天依然如此。Charlie和我——以及我们的董事——相信这一信条将在未来许多年里为伯克希尔服务良好。</p><p>伯克希尔的持股如今分布在五个大&quot;桶&quot;中，其中一个由我这位&quot;创始人&quot;占据。这个桶必然会空，因为我持有的股份将逐年分配给各种慈善机构。</p><p>其余四个桶中有两个由机构投资者填充，每个都管理着他人的资金。然而，这就是它们相似之处终结的地方：它们的投资程序截然不同。</p><p>其中一个机构桶是指数基金——投资世界中一个庞大且不断增长的领域。这些基金 simply模仿它们追踪的指数。指数投资者最青睐的是标普500，伯克希尔是其成分股。必须强调的是，指数基金持有伯克希尔股份仅仅是因为它们必须这样做。它们处于自动驾驶状态，买卖只是为了&quot;权重&quot;目的。</p><p>另一个机构桶中是专业人士，他们管理客户的钱款，无论是富人个人、大学、养老金领取者还是其他任何人。这些专业经理人的使命是根据他们对估值和前景的判断，将资金从一个投资转移到另一个。这是一个光荣——尽管困难——的职业。</p><p>我们很乐意 为这个&quot;主动&quot;群体服务，因为他们同时在为客户的资金寻找更好的配置场所。当然，一些经理人有长期视角，交易非常频繁。其他人则使用可能在一纳秒内指导股票买卖的计算机算法。一些专业投资者会根据他们的宏观经济判断来去自由。</p><p>我们的第四个桶由个人股东组成，他们的行为方式与上述主动型机构管理者相似。这些股东理所当然地认为，当他们看到另一个令他们兴奋的投资时，伯克希尔股份可能是资金来源之一。我们对这种态度没有异议，这与我们在伯克希尔持有的某些股票的看法类似。</p><p>尽管如此，如果Charlie和我对第五个桶没有特殊感情，那我们就不是人：这个桶包含一百多万个人投资者，他们 simply信任我们代表他们的利益，无论未来如何。他们加入我们时不打算离开，心态与我们最初合伙人相似。</p><hr><p>是的，我们合伙企业时代的许多投资者，以及他们的后代，至今仍持有伯克希尔的大量股票。</p><p>这些老投资者的典型代表是Stan Truhsen，一位乐观慷慨的奥马哈眼科医生，也是我的私人朋友，他于2020年11月13日迎来了百岁生日。1959年，Stan与其他十位年轻的奥马哈医生共同组建了与我的合伙企业。这些医生颇具创意地将他们的企业命名为Emdee有限公司。他们每年都与我妻子一同参加在我们家中举办的庆祝晚宴。</p><p>当我们的合伙企业于1969年分配伯克希尔股票时，所有医生都保留了所获得的股票。他们或许并不精通投资或会计，但他们知道在伯克希尔他们会被视为合伙人。</p><p>Stan在Emdee的两位战友如今都已年逾九十，仍继续持有伯克希尔股票。这个群体的惊人持久力——加上Charlie和我分别为97岁和90岁的事实——提出了一个有趣的问题：伯克希尔的股东是否特别长寿？</p><p>伯克希尔这一独特而宝贵的个人投资者群体或许有助于理解我们不愿迎合华尔街分析师和机构投资者。我们已经有了想要的投资者，并不认为替换他们会带来整体上的升级。</p><p>伯克希尔的股东席位是有限的——也就是说，流通股份是有限的。我们非常喜爱已经占据这些席位的人。</p><p>当然，&quot;合伙人&quot;会有一些更替。然而，Charlie和我希望这种更替能够保持在最低水平。毕竟，谁会寻求频繁更换朋友、邻居或婚姻伴侣呢？</p><p>1958年，<a href="/04_people/菲利普·费雪.html">菲利普·费雪</a>撰写了一本关于投资的杰出著作。在书中，他将以公开公司比作经营餐厅。他说，如果你正在寻找食客，你可以凭借汉堡配可乐或法式美食配异国葡萄酒来吸引顾客并 prosper。但<a href="/04_people/菲利普·费雪.html">菲利普·费雪</a>警告说，你不能朝令夕改：你向潜在顾客传递的信息必须与他们在进入你的场所后发现的内容一致。</p><p>在伯克希尔，我们56年来一直提供汉堡和可乐。我们珍视这一餐饮所吸引的顾客群体。</p><p>美国和全球其他地区的数千万投资者和投机者有着广泛的选择来满足他们的口味。他们会发现拥有诱人想法的CEO和市场大师。如果他们想要目标价位、管理层盈利预测和&quot;故事&quot;，他们不会缺少追求者。&quot;技术派&quot;会自信地告诉他们图表上的某些波动预示着股票的下一步走势。行动号召永远不会停止。</p><p>应该指出的是，这些投资者中会有相当一部分做得很好。毕竟，股票所有权是一种&quot;正和&quot;游戏。的确，一只耐心且冷静的猴子，通过向一块列出标普500所有成分股的板子投掷50支飞镖来构建投资组合，只要不被迫改变其原始&quot;选择&quot;，随着时间推移将享受到股息和资本增值。</p><p>生产性资产如农场、房地产以及企业所有权会产生大量财富。大多数此类资产的所有者都会获得回报。所需要的只是时间、内心平静、充分的多元化，以及最小化的交易和费用。然而，投资者必须永远记住，他们的费用就是华尔街的收入。而且，与我的猴子不同，华尔街人士不是免费工作的。</p><p>当伯克希尔的席位出现空缺时——我们希望这样的空缺很少——我们希望由理解和渴望我们所提供产品的新股东来填补。经过数十年的管理，Charlie和我仍然无法保证业绩。但我们能够而且确实承诺将你们视为合伙人。</p><p>我们的继任者也将如此。</p><p>一个可能令你惊讶的伯克希尔数字</p><p>最近，我了解到关于我们公司的一个事实，这是我从未怀疑过的：伯克希尔拥有位于美国的物业、厂房和设备——构成我国&quot;商业基础设施&quot;的资产——其GAAP估值超过任何其他美国公司。伯克希尔这些国内&quot;固定资产&quot;的折旧后成本为1540亿美元。该榜单上的下一位是AT&amp;T，其物业、厂房和设备为1270亿美元。</p><p>我应该指出，伯克希尔在固定资产所有权方面的领先地位本身并不代表投资胜利。最佳业绩出现在那些只需 minimal资产就能开展高利润业务的公司——并提供只需要少量额外资本就能扩大销售额的商品或服务。事实上，我们拥有几家这样的杰出企业，但它们规模相对较小，最多只能缓慢增长。</p><p>然而，资产密集型公司也可以是不错的投资。事实上，我们对我们两大巨头——BNSF和BHE——感到满意：2011年，即伯克希尔完全拥有BNSF的第一年，两家公司合计盈利42亿美元。在2020年这个对许多企业来说艰难的一年，这对组合赚了83亿美元。</p><p>BNSF和BHE在未来数十年将需要大量资本支出。好消息是，两家公司很可能在增量投资上获得适当的回报。</p><p>让我们先看BNSF。你的铁路运输了美国境内约15%的非本地吨英里（一吨货物运输一英里）的货物，无论通过铁路、卡车、管道、驳船还是飞机运输。BNSF的运量显著领先于其他任何承运商。</p><p>美国铁路的历史引人入胜。经过约150年的狂热建设、欺骗、过度建设、破产、重组和合并，铁路行业在几十年前终于成熟并合理化。</p><p>BNSF于1850年开始运营，当时是伊利诺伊州东北部的一条12英里线路。如今，它拥有390条前身，其铁路已被收购或合并。该公司的详细历史可在<a href="http://www.bnsf.com/bnsf-resources/pdf/about-bnsf/History_and_Legacy.pdf%E4%B8%8A%E6%9F%A5%E9%98%85%E3%80%82" target="_blank" rel="noreferrer">http://www.bnsf.com/bnsf-resources/pdf/about-bnsf/History_and_Legacy.pdf上查阅。</a></p><p>伯克希尔于2010年初收购了BNSF。自我们收购以来，铁路已在固定资产上投资410亿美元，支出超过其折旧费用200亿美元。铁路运输是户外运动，特点是长达一英里的列车必须在极寒和极热中可靠运行，同时穿越从沙漠到山区的各种地形。大规模洪水定期发生。BNSF拥有23000英里轨道，遍布28个州，必须不惜代价最大化其广阔系统的安全和服务。</p><p>尽管如此，BNSF已向伯克希尔支付大量股息——总计418亿美元。然而，铁路只向我们支付满足其业务需求和维持约20亿美元现金余额后的剩余部分。这一保守政策使BNSF能够以低利率借款，无需伯克希尔为其债务提供担保。</p><p>关于BNSF还有一点要说明：去年，其CEO Carl Ice和他的副手Katie Farmer在应对业务显著下滑的同时，在控制费用方面表现出色。尽管货运量下降了7%，两人实际上将BNSF的利润率提高了2.9个百分点。Carl按照原计划在年底退休，Katie接任CEO。你的铁路掌握在可靠的人手中。</p><p>与BHE不同，BHE在其普通股上不支付股息，这在电力公用事业行业中极为不寻常。这一节俭政策在我们21年所有权期间一直存在。与铁路不同，美国的电力公用事业需要进行大规模改造，最终成本将是惊人的。这一努力将吸收BHE未来几十年的全部收益。我们欢迎这一挑战，并相信追加投资将获得适当的回报。</p><p>让我告诉你BHE的一项努力——其180亿美元的承诺，用于改造和扩展现在西部输电的大量过时电网。BHE于2006年启动该项目，预计将于2030年完成——是的，2030年。</p><p>可再生能源的到来使我们的项目成为社会必要。历史上，长期占主导地位的燃煤发电设施位于人口密集的中心附近。然而，风能和太阳能新世界的最佳选址往往在偏远地区。当BHE在2006年评估形势时，投资西部输电线路需要进行巨额投资已是公开秘密。然而，在计算项目成本后，很少有公司或政府实体有能力出手。</p><p>应该指出，BHE继续推进的决定是基于其对美国政治、经济和司法体系的信任。在产生可观收入之前，需要投入数十亿美元。输电线路必须跨越州和其他司法管辖区的边界，每个都有其自己的规则和利益相关者。BHE还需要与数百名土地所有者打交道，并与发电可再生能源的供应商和将电力分配给客户的远处公用事业公司签订复杂合同。竞争利益和旧秩序的捍卫者，以及渴望立即进入新世界的不切实际的空想家，都必须参与其中。</p><p>惊喜和延误是必然的。同样可以肯定的是，BHE拥有管理人才、机构承诺和财务能力来实现其承诺。虽然我们的西部输电项目还需要多年才能完成，但我们今天正在寻找其他类似规模的项目来承担。</p><p>无论障碍如何，BHE将成为提供更清洁能源的领导者。</p><p>年度股东大会</p><p>去年2月22日，我写信给你们告知我们盛大的年度股东大会计划。一个月内，这一安排被打乱了。</p><p>由Melissa Shapiro和伯克希尔首席财务官Marc Hamburg领导的总部团队迅速重组。令人奇迹般的是，他们的临时应变方案奏效了。伯克希尔副董事长之一Greg Abel与我在舞台上面对黑暗的竞技场、18000个空座位和一台摄像机。没有排练：Greg和我在&quot;演出时间&quot;前约45分钟到达。</p><p>Debbie Bosanek，我不可思议的助理，47年前17岁时加入伯克希尔，整理了约25张幻灯片，展示了我在家中收集的各种事实和数据。一支匿名但高度能的电脑和摄像机操作团队将幻灯片按正确顺序投射到屏幕上。</p><p>Yahoo向创纪录规模的国际观众直播了会议过程。CNBC的Becky Quick在新泽西州的家中，从股东事先提交的数千个问题中筛选，或在Greg和我在舞台上的四小时内通过电子邮件发送给她的问题中进行选择。&quot;花生脆糖和软糖&quot;，加上可口可乐，为我们提供了营养。</p><p>今年5月1日，我们计划更进一步。我们将再次依靠Yahoo和CNBC出色完成直播。Yahoo将在美国东部夏令时下午1点开始直播。只需访问<a href="https://finance.yahoo.com/brklivestream%E3%80%82" target="_blank" rel="noreferrer">https://finance.yahoo.com/brklivestream。</a></p><p>我们的正式会议将于美国东部夏令时下午5点开始，预计在5:30之前结束。在之前的下午1:30至5:00之间，我们将通过Becky转达来回答你们的问题。和以往一样，我们事先不知道会被问到什么问题。请将你们的难题发送至BerkeshireQuestions@cnbc.com。Yahoo将在5:30后结束会议。</p><p>现在——请敲鼓——一个惊喜。今年我们的会议将在洛杉矶举行……Charlie将与我同台，在31⁄2小时的问题环节中提供答案和观察。我去年想念他，更重要的是，你们明显想念他。我们其他宝贵的副董事长<a href="/04_people/阿吉特·贾恩.html">阿吉特·贾恩</a>和Greg Abel将与他们领域相关的问题一起出席。</p><p>通过Yahoo加入我们。把你们真正棘手的问题发给Charlie！我们会玩得开心，希望你们也是。</p><p>当然，更好的是能够面对面见到你们的日子。我希望并预计那将在2022年。</p><p>奥马哈的市民、我们参展的子公司以及我们总部所有人都迫不及待地想要为你们举办一场真正的年度股东大会，伯克希尔风格的。</p><p>2021年2月27日 沃伦·E·<a href="/04_people/沃伦·巴菲特.html">沃伦·巴菲特</a> 董事长</p>',110)])])}const m=e(r,[["render",l]]);export{s as __pageData,m as default};
